// Ambil data dari MQTT payload
const data = msg.payload;
const topic = msg.topic; // city/zone1/traffic

// Ekstrak zone dari topic: city/{zone}/traffic
const topicParts = topic.split('/');
const zone = topicParts[1]; // zone1, zone2, dst

// Validasi field wajib
if (!data.vehicle_density || !data.avg_speed_kmh) {
    node.warn(`[Traffic] Payload tidak lengkap dari topic: ${topic}`);
    return null;
}

// Map zone ke zone_id sesuai database
const zoneMap = {
    'zone1': 1,
    'zone2': 2,
    'zone3': 3,
    'zone4': 4,
    'zone5': 5
};

const zoneId = zoneMap[zone];
if (!zoneId) {
    node.warn(`[Traffic] Zone tidak dikenal: ${zone}`);
    return null;
}

// Transform ke format yang diharapkan PHP Traffic Service
const transformedPayload = {
    zone_id:          zoneId,
    vehicle_density:  Math.round(data.vehicle_density),
    avg_speed_kmh:    parseFloat(data.avg_speed_kmh.toFixed(2)),
    incident_flag:    data.incident_flag || 0,
    sensor_source:    data.sensor_id || `MQTT-${zone.toUpperCase()}-01`,
    recorded_at:      data.timestamp || new Date().toISOString(),
    // Metadata tambahan
    _meta: {
        source:    'mqtt',
        topic:     topic,
        zone:      zone,
        zone_name: data.zone_name || zone,
        received_at: new Date().toISOString()
    }
};

// Set URL dan headers untuk HTTP request ke Gateway
const gatewayUrl = env.get('GATEWAY_URL') || 'http://api-gateway:3000';
const iotToken   = env.get('IOT_TOKEN')   || '';

msg.url     = `${gatewayUrl}/iot/traffic`;
msg.method  = 'POST';
msg.payload = transformedPayload;
msg.headers = {
    'Content-Type':  'application/json',
    'Authorization': `Bearer ${iotToken}`,
    'X-Device-ID':   data.sensor_id || `MQTT-${zone.toUpperCase()}-01`,
    'X-Source':      'node-red-bridge',
    'X-Zone':        zone
};

node.log(`[Traffic] Zone ${zone} (id:${zoneId}) density:${transformedPayload.vehicle_density} speed:${transformedPayload.avg_speed_kmh}`);

return msg;

const status = msg.statusCode;
const body   = msg.payload;

if (status === 200 || status === 201) {
    node.log(`[Traffic] ✓ Berhasil POST ke gateway: ${status}`);
    // Kirim ke debug output
    msg.payload = {
        success:     true,
        status_code: status,
        response:    body,
        timestamp:   new Date().toISOString()
    };
    return [msg, null];
} else if (status === 429) {
    node.warn(`[Traffic] Rate limited (429). Akan retry setelah 5 detik.`);
    // Simpan ke antrian lokal
    msg.payload = {
        success: false,
        reason:  'rate_limited',
        retry:   true,
        data:    msg.payload
    };
    return [null, msg];
} else {
    node.error(`[Traffic] Gateway error: ${status} - ${JSON.stringify(body)}`);
    msg.payload = {
        success:     false,
        status_code: status,
        error:       body,
        timestamp:   new Date().toISOString()
    };
    return [null, msg];
}

// Gateway down — simpan ke antrian lokal Node-RED
node.warn(`[Traffic] Gateway tidak bisa dijangkau: ${msg.error}`);

msg.payload = {
    success:    false,
    reason:     'gateway_down',
    error:      msg.error,
    original:   msg.payload,
    queued_at:  new Date().toISOString()
};

return msg;

// Simpan ke context lokal Node-RED saat gateway down
const queue = context.get('traffic_queue') || [];

queue.push({
    payload:   msg.payload,
    queued_at: new Date().toISOString()
});

// Batasi queue maksimal 100 item
if (queue.length > 100) {
    queue.shift(); // hapus yang paling lama
    node.warn('[Traffic] Queue penuh (100), item lama dihapus');
}

context.set('traffic_queue', queue);
node.warn(`[Traffic] Data disimpan ke antrian lokal. Queue size: ${queue.length}`);

msg.payload = { queued: true, queue_size: queue.length };
return msg;

const queue = context.get('traffic_queue') || [];

if (queue.length === 0) {
    node.log('[Traffic] Queue kosong, tidak ada yang perlu di-retry.');
    return null;
}

node.log(`[Traffic] Mencoba retry ${queue.length} item dari queue lokal...`);

const messages = [];
const gatewayUrl = env.get('GATEWAY_URL') || 'http://api-gateway:3000';
const iotToken   = env.get('IOT_TOKEN')   || '';

// Ambil semua item dari queue dan kirim ulang
for (const item of queue) {
    messages.push({
        url:     `${gatewayUrl}/iot/traffic`,
        method:  'POST',
        payload: item.payload.original || item.payload,
        headers: {
            'Content-Type':  'application/json',
            'Authorization': `Bearer ${iotToken}`,
            'X-Source':      'node-red-retry'
        }
    });
}

// Kosongkan queue setelah retry
context.set('traffic_queue', []);

// Return pesan pertama (Node-RED akan proses satu per satu)
if (messages.length > 0) {
    return messages[0];
}
return null;

const data  = msg.payload;
const topic = msg.topic; // city/zone1/air

// Ekstrak zone dari topic
const topicParts = topic.split('/');
const zone = topicParts[1];

// Validasi field wajib
if (data.pm25 === undefined || data.temperature === undefined) {
    node.warn(`[Air] Payload tidak lengkap dari topic: ${topic}`);
    return null;
}

// Map zone ke zone_id
const zoneMap = {
    'zone1': 1,
    'zone2': 2,
    'zone3': 3,
    'zone4': 4,
    'zone5': 5
};

const zoneId = zoneMap[zone];
if (!zoneId) {
    node.warn(`[Air] Zone tidak dikenal: ${zone}`);
    return null;
}

// Tentukan alert level berdasarkan PM2.5 (WHO standard)
let alertLevel = null;
if (data.pm25 > 150) {
    alertLevel = 'hazardous';
} else if (data.pm25 > 55) {
    alertLevel = 'unhealthy';
} else if (data.pm25 > 35) {
    alertLevel = 'moderate';
}

// Jika anomali terdeteksi dari simulator, log warning
if (data.is_anomaly) {
    node.warn(`[Air] ANOMALY terdeteksi di ${zone}! PM2.5=${data.pm25}`);
}

// Transform ke format yang diharapkan PHP Environment Service
const transformedPayload = {
    zone_id:     zoneId,
    pm25:        parseFloat(data.pm25.toFixed(3)),
    pm10:        parseFloat(data.pm10.toFixed(3)),
    no2:         parseFloat(data.no2.toFixed(3)),
    co:          parseFloat(data.co.toFixed(3)),
    o3:          parseFloat(data.o3.toFixed(3)),
    temperature: parseFloat(data.temperature.toFixed(2)),
    humidity:    parseFloat(data.humidity.toFixed(2)),
    sensor_id:   data.sensor_id || `ENV-${zone.toUpperCase()}-01`,
    recorded_at: data.timestamp || new Date().toISOString(),
    // Metadata tambahan
    _meta: {
        source:      'mqtt',
        topic:       topic,
        zone:        zone,
        zone_name:   data.zone_name || zone,
        is_anomaly:  data.is_anomaly || false,
        alert_level: alertLevel,
        received_at: new Date().toISOString()
    }
};

const gatewayUrl = env.get('GATEWAY_URL') || 'http://api-gateway:3000';
const iotToken   = env.get('IOT_TOKEN')   || '';

msg.url     = `${gatewayUrl}/iot/air`;
msg.method  = 'POST';
msg.payload = transformedPayload;
msg.headers = {
    'Content-Type':  'application/json',
    'Authorization': `Bearer ${iotToken}`,
    'X-Device-ID':   data.sensor_id || `ENV-${zone.toUpperCase()}-01`,
    'X-Source':      'node-red-bridge',
    'X-Zone':        zone
};

node.log(`[Air] Zone ${zone} (id:${zoneId}) PM2.5:${transformedPayload.pm25} Temp:${transformedPayload.temperature}°C${data.is_anomaly ? ' ⚠ ANOMALY' : ''}`);

return msg;

const status = msg.statusCode;
const body   = msg.payload;

if (status === 200 || status === 201) {
    node.log(`[Air] ✓ Berhasil POST ke gateway: ${status}`);
    msg.payload = {
        success:     true,
        status_code: status,
        response:    body,
        timestamp:   new Date().toISOString()
    };
    return [msg, null];
} else if (status === 429) {
    node.warn('[Air] Rate limited (429). Data disimpan ke antrian lokal.');
    msg.payload = { success: false, reason: 'rate_limited', retry: true, data: msg.payload };
    return [null, msg];
} else {
    node.error(`[Air] Gateway error: ${status} - ${JSON.stringify(body)}`);
    msg.payload = { success: false, status_code: status, error: body };
    return [null, msg];
}

node.warn(`[Air] Gateway tidak bisa dijangkau: ${msg.error}`);
msg.payload = {
    success:   false,
    reason:    'gateway_down',
    error:     msg.error,
    original:  msg.payload,
    queued_at: new Date().toISOString()
};
return msg;

const queue = context.get('air_queue') || [];

queue.push({ payload: msg.payload, queued_at: new Date().toISOString() });

if (queue.length > 100) {
    queue.shift();
    node.warn('[Air] Queue penuh (100), item lama dihapus');
}

context.set('air_queue', queue);
node.warn(`[Air] Data disimpan ke antrian lokal. Queue size: ${queue.length}`);

msg.payload = { queued: true, queue_size: queue.length };
return msg;

const queue = context.get('air_queue') || [];

if (queue.length === 0) {
    node.log('[Air] Queue kosong.');
    return null;
}

node.log(`[Air] Retry ${queue.length} item dari queue lokal...`);

const gatewayUrl = env.get('GATEWAY_URL') || 'http://api-gateway:3000';
const iotToken   = env.get('IOT_TOKEN')   || '';

const item = queue.shift();
context.set('air_queue', queue);

return {
    url:     `${gatewayUrl}/iot/air`,
    method:  'POST',
    payload: item.payload.original || item.payload,
    headers: {
        'Content-Type':  'application/json',
        'Authorization': `Bearer ${iotToken}`,
        'X-Source':      'node-red-retry'
    }
};

const data = msg.payload;

if (data.status === 'online') {
    node.log(`[Status] IoT Simulator ONLINE - zones: ${JSON.stringify(data.zones)} interval: ${data.interval}s`);
} else if (data.status === 'offline') {
    node.warn('[Status] IoT Simulator OFFLINE!');
}

msg.payload = {
    event:     'simulator_status',
    status:    data.status,
    zones:     data.zones,
    interval:  data.interval,
    timestamp: data.timestamp
};

return msg;

const status = msg.statusCode;
const body   = msg.payload;

if (status === 200 && body.data && body.data.gateway === 'healthy') {
    node.log('[Health] Gateway SEHAT ✓');
    msg.payload = { gateway: 'healthy', uptime: body.data.uptime_seconds };
} else {
    node.warn(`[Health] Gateway bermasalah: ${status}`);
    msg.payload = { gateway: 'unhealthy', status_code: status };
}

return msg;

node.error(`[Health] Gateway tidak bisa dijangkau! Error: ${msg.error}`);
msg.payload = { gateway: 'down', error: msg.error, timestamp: new Date().toISOString() };
return msg;
